definition.script:
pipeline {
    agent any
    stages {
        stage('Configure Open Access') {
            steps {
                script {
                    def result = build job: 'Enable Explore Without Login', parameters: [
                        [$class: 'BooleanParameterValue', name: 'ENABLE_OPEN_ACCESS', value: env.ENABLE_OPEN_ACCESS.toBoolean()]
                    ]
                }
            }
        }

        stage('Rebuild Frontend') {
            steps {
                script {
                    def result = build job: 'PIC-SURE Frontend Build', parameters: [
                        [$class: 'StringParameterValue', name: 'pipeline_build_id', value: 'MANUAL_RUN'],
                        [$class: 'StringParameterValue', name: 'git_hash', value: env.FRONTEND_GIT_HASH]
                    ]
                }
            }
        }

        stage('Deploy') {
            steps {
                script {
                    def result = build job: 'Start PIC-SURE'
                }
            }
        }
    }
}
